#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
#define Clear(a) memset(a,0,sizeof(a))
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=2e5+10,M=4e5+10;const long long INF=4e18;
struct Graph
{
	int head[N],des[M],nxt[M],val[M],cnt;
	inline void ins(int x,int y,int z){des[++cnt]=y;nxt[cnt]=head[x];val[cnt]=z;head[x]=cnt;}
	inline void Init(){Clear(head);cnt=0;}
}a;
struct Sort
{
	int pos,cst;inline bool operator == (const Sort &x)const{return pos==x.pos;}
	inline bool operator<(const Sort &x)const{return pos^x.pos?pos<x.pos:cst<x.cst;}
}Q[N];int que[N],H,T,dp[N],deg[N],top,stk[N];
inline void topo(int n,int s)
{
	dp[s]=0;H=1,T=0;rep(1,n,i)if(!deg[i])que[++T]=i;
	while(H<=T)
	{
		int u=que[H++];grep(a,u,i)
		{
			int v=a.des[i];dp[v]=min(dp[v],dp[u]+a.val[i]);
			if(!(--deg[v]))que[++T]=v;
		}
//		printf("%d\n",u);
	}
}
signed main()
{
//	freopen("ddtt.txt","r",stdin);freopen("qwq.txt","w",stdout);
	int qn=read(),s=read(),t=read();rep(1,qn,i)Q[i].cst=read(),Q[i].pos=read();
	Q[++qn].pos=t;Q[qn].cst=0;sort(Q+1,Q+qn+1);int n=unique(Q+1,Q+qn+1)-Q-1;int l,r,res,mid;
	l=1;r=n;res=0;while(l<=r)Q[mid=(l+r)>>1].pos<=s?(l=mid+1,res=mid):(r=mid-1);s=res;
	l=1;r=n;res=0;while(l<=r)Q[mid=(l+r)>>1].pos<=t?(l=mid+1,res=mid):(r=mid-1);t=res;
//	rep(1,n,i)printf("g%lld %lld\n",Q[i].pos,Q[i].cst);printf("p%lld %lld\n",s,t);
	rep(1,n,i)
	{
		while(top&&Q[stk[top]].cst>=Q[i].cst)top--;
		if(top)a.ins(i,stk[top],(Q[i].pos-Q[stk[top]].pos)*Q[i].cst),++deg[stk[top]];
		if(i^s)stk[++top]=i;
	}
	top=0;drep(n,1,i)
	{
		while(top&&Q[stk[top]].cst>=Q[i].cst)top--;
		if(top)a.ins(i,stk[top],(Q[stk[top]].pos-Q[i].pos)*Q[i].cst),++deg[stk[top]];
		if(i^s)stk[++top]=i;
	}
//	rep(1,n,u)grep(a,u,i)printf("%lld' %lld' %lld\n",u,a.des[i],a.val[i]);
	rep(1,n,i)dp[i]=INF;topo(n,s);printf("%lld\n",dp[t]);return 0;
}
